impl.spec_text:
trait T { spec fn f(&self) -> bool; }
struct S<A> { a: A }
impl T for S<u8> { spec fn f(&self) -> bool { true } }
impl T for S<bool> { spec fn f(&self) -> bool { false } }
proof fn test(x: S<u8>, y: S<bool>) {
    assert(x.f());
    assert(!y.f());
}

